/// <summary>
/// The ETGSOWorkflowTypeNewEventHandler workflow event handler.
/// </summary>
public class  ETGSOWorkflowTypeNewEventHandler implements WorkflowCanceledEventHandler,  
	WorkflowCompletedEventHandler,
	WorkflowStartedEventHandler
{

}

Method.Source:
// Can be used in future for business process
public void started(WorkflowEventArgs _workflowEventArgs)
{

}

public void completed(WorkflowEventArgs _workflowEventArgs)
{


    RecId documentRecId = _workflowEventArgs.parmWorkflowContext().parmRecId();

    SalesTable::updateWorkflowStatus(documentRecId, VersioningDocumentState::Approved);


}

public void changeRequested(WorkflowElementEventArgs _workflowElementEventArgs)
{
    RecId documentRecId = _workflowElementEventArgs.parmWorkflowContext().parmRecId();
    SalesTable::updateWorkflowStatus(documentRecId, VersioningDocumentState::Draft);
}

private void clearWorkFlowState(WorkflowEventArgs _workflowEventArgs)
{
    WorkflowContext workflowContext = _workflowEventArgs.parmWorkflowContext();
    RecId salesRecId = workflowContext.parmRecId();

    ttsbegin;
    SalesTable sales = SalesTable::findRecId(salesRecId, true);
    sales.ETGWorkflowStatus = VersioningDocumentState::Draft;
    sales.update();
    ttscommit;
}
